if (!function_exists('select2')) {
    function select2($idSelect)
    {
        $data = old($idSelect) == null ? null : array_diff([json_encode(old($idSelect))], [""]);
        if ($data != null) :
            return "
                    $('#" . $idSelect . "').val(" . $data[0] . ");
                    $('#" . $idSelect . "').trigger('change');
                    ";
        endif;

        return '';
    }
}

if (!function_exists('select2_modal')) {
    function select2_modal($idSelect, $idModal)
    {
        $select2 = '$("#' . $idSelect . '").select2({
            dropdownParent: $("#' . $idModal . '")
        });';

        $data = old($idSelect) == null ? null : array_diff([json_encode(old($idSelect))], [""]);
        if ($data != null) :
            $select2 .= "
                    $('#" . $idSelect . "').val(" . $data[0] . ");
                    $('#" . $idSelect . "').trigger('change');
                    ";
        endif;

        return $select2;
    }
}

if (!function_exists('kurensi_singkat')) {
    function kurensi_singkat()
    {
        return "
        function kurensi_singkat(angka) {
            if (angka == 0) {
                return 0;
            }
            if (angka > 0 && angka < 1000000) {
                let bagi = angka / 1000;
                return bagi + ' rb';
            }
            if (angka >= 1000000) {
                let bagi = angka / 1000000;
                return bagi + ' jt';
            }
        }
        ";
    }
}

