if (!function_exists('notifikasi')) {
    function notifikasi()
    {
        return "
        function notifikasi(type, posisi, pesan) {
            Codebase.helpers('jq-notify', {
                align: posisi,             // 'right', 'left', 'center'
                from: 'top',                // 'top', 'bottom'
                type: type,               // 'info', 'success', 'warning', 'danger'
                icon: type == 'info' ? 'fa fa-circle-info me-2' : (type == 'success' ? 'fa fa-circle-check me-2' : 'fa fa-bug me-2'),    // Icon class
                message: pesan
            });
        };
        ";
    }
}

